import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.math.BigDecimal;
import java.math.RoundingMode;

/**
 * TAXCALC - combined payroll withholding, translated from COBOL 85.
 * Faithful variant: exact COBOL arithmetic behavior takes priority over
 * Java idiom. The PERFORM CALC-STATE THRU CALC-LOCAL range runs all three
 * withholding paragraphs (state, federal, local), each ROUNDED half away
 * from zero into PIC 9(7)V99; the total is their sum and NET is the gross
 * less that total. Every store honors the target PICTURE's scale and
 * capacity (high-order digits drop silently, as COBOL does with no ON
 * SIZE ERROR declared).
 */
public final class Taxcalc {

    /** WS-STATE-RATE PIC 99V99 VALUE 5.00 (percent). */
    private static final BigDecimal STATE_RATE = new BigDecimal("5.00");

    /** WS-FED-RATE PIC 99V99 VALUE 15.00 (percent). */
    private static final BigDecimal FED_RATE = new BigDecimal("15.00");

    /** WS-LOCAL-RATE PIC 99V99 VALUE 2.00 (percent). */
    private static final BigDecimal LOCAL_RATE = new BigDecimal("2.00");

    /** PIC 9(7)V99 capacity (WS-GROSS, the taxes, WS-NET). */
    private static final BigDecimal PIC_9_7_V99_MODULUS = new BigDecimal("10000000");

    public static void main(String[] args) throws IOException {
        BufferedReader in = new BufferedReader(new InputStreamReader(System.in));

        // MAIN-PARA (taxcalc.cbl:36-45): ACCEPT + FUNCTION NUMVAL.
        String empId = readLine(in);                                        // WS-EMP-ID PIC X(8)
        BigDecimal gross = numval(readLine(in), 2, PIC_9_7_V99_MODULUS);    // WS-GROSS PIC 9(7)V99

        // PERFORM CALC-STATE THRU CALC-LOCAL (taxcalc.cbl:40): the whole
        // withholding range runs, one ROUNDED component per paragraph.
        BigDecimal stateTax = withhold(gross, STATE_RATE);  // CALC-STATE (taxcalc.cbl:46-47)
        BigDecimal fedTax = withhold(gross, FED_RATE);      // CALC-FEDERAL (taxcalc.cbl:48-49)
        BigDecimal localTax = withhold(gross, LOCAL_RATE);  // CALC-LOCAL (taxcalc.cbl:50-51)

        // COMPUTE WS-TOTAL-TAX = state + fed + local (taxcalc.cbl:41-42).
        BigDecimal totalTax = stateTax.add(fedTax).add(localTax).remainder(PIC_9_7_V99_MODULUS);
        // COMPUTE WS-NET = WS-GROSS - WS-TOTAL-TAX (taxcalc.cbl:43).
        BigDecimal net = gross.subtract(totalTax).remainder(PIC_9_7_V99_MODULUS);

        // PRINT-PARA (taxcalc.cbl:52-57): KEY=VALUE contract on stdout.
        StringBuilder out = new StringBuilder();
        out.append("EMP_ID=").append(empId).append('\n');
        out.append("TAX=").append(totalTax.toPlainString()).append('\n');
        out.append("NET=").append(net.toPlainString()).append('\n');
        System.out.print(out);
    }

    /**
     * One withholding component: COMPUTE tax ROUNDED = gross * rate / 100.
     * The /100 is an exact decimal shift; ROUNDED settles half away from
     * zero into PIC 9(7)V99, then capacity applies.
     */
    private static BigDecimal withhold(BigDecimal gross, BigDecimal ratePercent) {
        return gross.multiply(ratePercent)
                .movePointLeft(2)
                .setScale(2, RoundingMode.HALF_UP)
                .remainder(PIC_9_7_V99_MODULUS);
    }

    private static String readLine(BufferedReader in) throws IOException {
        String line = in.readLine();
        return line == null ? "" : line.trim();
    }

    /**
     * FUNCTION NUMVAL followed by the COMPUTE store into the target
     * PICTURE: extra decimals truncate toward zero and integer digits
     * beyond the PICTURE's capacity drop silently. COBOL input-conversion
     * behavior with no ON SIZE ERROR declared.
     */
    private static BigDecimal numval(String s, int scale, BigDecimal capacity) {
        try {
            BigDecimal v = new BigDecimal(s.trim());
            if (v.signum() < 0) {
                throw new NumberFormatException("negative value for unsigned PICTURE");
            }
            return v.setScale(scale, RoundingMode.DOWN).remainder(capacity);
        } catch (NumberFormatException e) {
            System.err.println("TAXCALC: invalid numeric input: " + s);
            System.exit(3);
            return BigDecimal.ZERO; // unreachable
        }
    }
}
